#!/usr/bin/env node
// =============================================================================
// Pre-build script: generates src/environments/api-config.generated.ts from
// the API_URL env var. Called automatically by the `prebuild` npm hook.
//
// The generated file is gitignored. Re-running the script overwrites it.
// If API_URL is unset, the generated file exports an empty string and the
// SPA must handle the missing value (typically the login page is shown
// with backend calls disabled).
//
// Usage:
//   API_URL=https://api.example.com npm run build
//   API_URL="" npm run build              # local dev with no backend
// =============================================================================

import { writeFileSync, mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const projectRoot = resolve(__dirname, '..');
const output = resolve(projectRoot, 'src/environments/api-config.generated.ts');

const apiUrl = process.env.API_URL ?? '';

const content =
  '// AUTO-GENERATED by scripts/pre-build-api-config.mjs. Do not edit.\n' +
  '// Generated at build time. Re-run `npm run prebuild` to regenerate.\n' +
  `// API_URL at generation: ${JSON.stringify(apiUrl)}\n` +
  '\n' +
  `export const API_URL = ${JSON.stringify(apiUrl)};\n`;

mkdirSync(dirname(output), { recursive: true });
writeFileSync(output, content);

console.log(
  `[pre-build] wrote ${output.replace(projectRoot + '\\', '')} (API_URL=${JSON.stringify(apiUrl)})`,
);
